    assert result == {'hello': 2, 'world': 1}

def test_case_insensitive():
    result = count_words('Hello HELLO hello')
    assert result == {'hello': 3}

def test_punctuation():
    result = count_words('Hello, world! Hello.')
    assert result == {'hello': 2, 'world': 1}

def test_empty():
    result = count_words('')
    assert result == {}

