startingFiles.test_groupby.js:
const { groupBy } = require('./groupby');

const tests = [
  {
    name: 'basic grouping',
    input: [{type: 'a', val: 1}, {type: 'b', val: 2}, {type: 'a', val: 3}],
    key: x => x.type,
    expected: { a: [{type: 'a', val: 1}, {type: 'a', val: 3}], b: [{type: 'b', val: 2}] }
  },
  {
    name: 'empty array',
    input: [],
    key: x => x,
    expected: {}
  },
  {
    name: 'number keys',
    input: [1, 2, 3, 4, 5],
    key: x => x % 2 === 0 ? 'even' : 'odd',
    expected: { odd: [1, 3, 5], even: [2, 4] }
  }
];

let passed = 0;
for (const t of tests) {
  const result = groupBy(t.input, t.key);
  const ok = JSON.stringify(result) === JSON.stringify(t.expected);
  console.log(ok ? `PASS: ${t.name}` : `FAIL: ${t.name}`);
  if (!ok) {
    console.log('  Expected:', JSON.stringify(t.expected));
    console.log('  Got:', JSON.stringify(result));
  }
  if (ok) passed++;
}
console.log(`\n${passed}/${tests.length} tests passed`);
process.exit(passed === tests.length ? 0 : 1);

